#include <stdio.h>
#define MOD 998244353
int main() {
    int N, r, K;
    scanf("%d", &N);
    int adj[N][N] = {{0}};
    for (int i = 0; i < N - 1; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        x--; y--;
        adj[x][y] = adj[y][x] = 1;
    }
    scanf("%d %d", &r, &K);
    r--;
    int dp[N][K + 1] = {{0}};
    dp[r][0] = 1;
    for (int k = 1; k <= K; k++) {
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (adj[i][j]) {
                    dp[i][k] = (dp[i][k] + dp[j][k - 1]) % MOD;
                }
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", dp[i][K]);
    }
    printf("\n");
    return 0;
}

