import java.util.Scanner;
public class Main {
    static final int MOD = 998244353;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[][] adj = new int[N][N];
        for (int i = 0; i < N - 1; i++) {
            int x = sc.nextInt() - 1;
            int y = sc.nextInt() - 1;
            adj[x][y] = adj[y][x] = 1;
        }
        int r = sc.nextInt() - 1;
        int K = sc.nextInt();
        int[][] dp = new int[N][K + 1];
        dp[r][0] = 1;
        for (int k = 1; k <= K; k++) {
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    if (adj[i][j] == 1) {
                        dp[i][k] = (dp[i][k] + dp[j][k - 1]) % MOD;
                    }
                }
            }
        }
        for (int i = 0; i < N; i++) {
            System.out.print(dp[i][K] + " ");
        }
        System.out.println();
    }
}

