dp[r - 1][0] = 1;
for (let k = 1; k <= K; k++) {
    for (let i = 0; i < N; i++) {
        for (let j = 0; j < N; j++) {
            if (adj[i][j] === 1) {
                dp[i][k] = (dp[i][k] + dp[j][k - 1]) % MOD;
            }
        }
    }
}
